export type StatefulEvt<T> = {
    current: T;
    subscribe: (next: (data: T) => void) => Subscription;
};
export type StatefulReadonlyEvt<T> = {
    readonly current: T;
    subscribe: (next: (data: T) => void) => Subscription;
};
export type Subscription = {
    unsubscribe: () => void;
};
export declare function createStatefulEvt<T>(getInitialValue: () => T): StatefulEvt<T>;
